mapper.select:
SELECT A.SCD_ID, A.SCD_SE, A.SCD_DEPT_ID, A.SCD_KIND_CODE, A.SCD_BGNDE, A.SCD_ENDDE, A.SCD_NM, A.SCD_DESC, A.SCD_PLACE, A.SCD_IPCR_CODE, A.SCD_CHARGER_ID, A.ATCH_FILE_ID, A.FRST_REGIST_PNTTM FRST_REGISTER_PNTTM, A.FRST_REGISTER_ID, A.LAST_UPDT_PNTTM, A.LAST_UPDUSR_ID, A.REPTIT_SE_CODE FROM acm_schedule_mst A WHERE 1=1
AND SCD_SE LIKE CONCAT ('%', #{searchKeyword},'%')
ORDER BY A.FRST_REGIST_PNTTM DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

mapper.insert:
